async (page) => {
  var title = "图解 Blaze · 第 7 章 · JOIN 与关联策略 — 图解 Blaze-Persistence";
  var html = "<section style=\"margin-bottom:24px;\">\n<h2 style=\"font-size:24px;font-weight:800;color:#1a1a2e;line-height:1.4;margin:0 0 8px;\">第 7 章 · JOIN 与关联策略</h2>\n</section>\n<section><p style=\"font-size:14px;color:#888;margin-bottom:28px;line-height:1.7;\">隐式 JOIN · 显式 JOIN · FETCH JOIN · ON 条件 · 关联路径</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #1e6fff22;border-radius:10px;padding:20px 22px 14px;margin:0 0 28px;line-height:1.9;\"><p style=\"font-size:15px;color:#2b2b2b;margin-bottom:10px;line-height:1.8;\">\n    关联查询是 ORM 中最容易产生性能问题的环节。Blaze-Persistence 在 JPA 的 JOIN 语义之上，\n    提供了<strong style=\"color:#1a1a2e;font-weight:700;\">隐式路径解析</strong>、<strong style=\"color:#1a1a2e;font-weight:700;\">多种 JOIN 类型</strong>、<strong style=\"color:#1a1a2e;font-weight:700;\">FETCH JOIN 优化</strong>\n    和<strong style=\"color:#1a1a2e;font-weight:700;\">Lateral JOIN</strong> 等高级能力，让开发者既能写出简洁的查询代码，又能精确控制底层 SQL 的关联策略。\n  </p><ul style=\"margin:8px 0 8px 20px;color:#2b2b2b;\"><li style=\"margin-bottom:4px;font-size:13px;\">理解隐式 JOIN 与显式 JOIN 的本质差异及其适用场景</li><li style=\"margin-bottom:4px;font-size:13px;\">掌握 INNER / LEFT / RIGHT / FULL 四种 JOIN 类型的 API</li><li style=\"margin-bottom:4px;font-size:13px;\">利用 FETCH JOIN 消除 N+1 查询，同时规避笛卡尔积</li><li style=\"margin-bottom:4px;font-size:13px;\">通过关联路径表达式进行多级实体导航</li><li style=\"margin-bottom:4px;font-size:13px;\">在 Entity View 层面选择最佳 FetchStrategy</li><li style=\"margin-bottom:4px;font-size:13px;\">识别常见 JOIN 陷阱与数据库兼容性限制</li></ul><p style=\"font-size:12px;color:#888;margin-top:10px;padding-top:10px;border-top:1px solid #e5e7eb;\">前置知识：<span style=\"color:#1e6fff;\">第 3 章 · CriteriaBuilder 查询引擎</span></p></section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">7.1 隐式 JOIN vs 显式 JOIN</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">\n  在 Blaze-Persistence 中，当你通过点号表达式（如 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">order.customer.name</code>）访问关联属性时，\n  框架会<strong style=\"color:#1a1a2e;font-weight:700;\">自动推断</strong>所需的 JOIN 并在生成的 JPQL / SQL 中隐式添加。\n  这种「路径导航触发关联」的机制称为<strong style=\"color:#1a1a2e;font-weight:700;\">隐式 JOIN</strong>。与之对应，\n  <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">join()</code> / <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">innerJoin()</code> 等 API 让你<strong style=\"color:#1a1a2e;font-weight:700;\">显式声明</strong>关联关系及其别名。\n</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">隐式 JOIN vs 显式 JOIN — 决策流程</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">order</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">customer</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">编写查询表达式</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #e6a817;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">◇ 是否包含点号路径?</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">隐式 JOIN</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">显式 JOIN</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">框架自动推断 JOIN 类型<br/>默认 LEFT JOIN</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">自动去重：<br/>相同路径只生成一次 JOIN</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">手动指定 JOIN 类型<br/>INNER / LEFT / RIGHT / FULL</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">可附加 ON 条件<br/>joinOn() API</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">获得可复用别名<br/>用于后续 WHERE / SELECT</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">生成 JPQL / SQL</p></section></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">隐式 JOIN 路径解析</h3></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">\n  隐式 JOIN 最大的优势是<strong style=\"color:#1a1a2e;font-weight:700;\">简洁</strong>——开发者只关注要访问的属性路径，\n  JOIN 的生成完全交给框架。Blaze-Persistence 会对路径进行解析，\n  按照实体元模型将每一段路径映射为相应的 SQL JOIN。\n</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">CriteriaBuilder&lt;Tuple&gt; cb = cbf.create(em, Tuple.class)<br/>    .from(Order.class, \"o\")<br/>    .select(\"o.customer.name\")          <span style=\"color:#6c7086;font-style:italic;\">// 隐式 LEFT JOIN Customer</span><br/>    .select(\"o.customer.address.city\")  <span style=\"color:#6c7086;font-style:italic;\">// 复用已有 JOIN + 追加 Address JOIN</span><br/>    .where(\"o.customer.vip\").eq(true)   <span style=\"color:#6c7086;font-style:italic;\">// 复用同一个 Customer JOIN</span><br/>    .orderByAsc(\"o.customer.name\");<br/><span style=\"color:#6c7086;font-style:italic;\">// 生成 SQL:</span><br/><span style=\"color:#6c7086;font-style:italic;\">// SELECT c.name, a.city FROM Order o</span><br/><span style=\"color:#6c7086;font-style:italic;\">//   LEFT JOIN Customer c ON o.customer_id = c.id</span><br/><span style=\"color:#6c7086;font-style:italic;\">//   LEFT JOIN Address  a ON c.address_id  = a.id</span><br/><span style=\"color:#6c7086;font-style:italic;\">// WHERE c.vip = true ORDER BY c.name</span></p></section>\n<section style=\"background:#f5f5f5;border:1px solid #1e6fff44;border-radius:8px;padding:14px 16px;margin:14px 0 20px;font-size:14px;line-height:1.8;color:#2b2b2b;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">路径去重：</strong>多次引用同一路径段（如 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">o.customer</code>）只会产生一次 JOIN，\n  Blaze-Persistence 内部通过路径注册表进行去重。\n</section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">显式 JOIN 声明</h3></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">\n  当你需要控制 JOIN 类型、附加额外 ON 条件或跨实体关联时，使用显式 JOIN API：\n</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">CriteriaBuilder&lt;Tuple&gt; cb = cbf.create(em, Tuple.class)<br/>    .from(Order.class, \"o\")<br/>    .innerJoin(\"o.customer\", \"c\")           <span style=\"color:#6c7086;font-style:italic;\">// 显式 INNER JOIN</span><br/>    .leftJoin(\"o.items\", \"i\")               <span style=\"color:#6c7086;font-style:italic;\">// 显式 LEFT JOIN</span><br/>    .select(\"c.name\")<br/>    .select(\"i.productName\")<br/>    .where(\"c.country\").eq(\"CN\");<br/><span style=\"color:#6c7086;font-style:italic;\">// 开发者完全控制 JOIN 类型与别名</span></p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">隐式 vs 显式 — SQL 生成对比</p><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">IMPLICIT</p><table style=\"width:100%;border-collapse:collapse;margin:4px 0;\"><tr><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">select('o.customer.name')\"] --> IB[\"框架推断:<br/>LEFT JOIN Customer c<br/>  ON o.customer_id = c.id</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">框架推断:<br/>LEFT JOIN Customer c<br/>  ON o.customer_id = c.id</p></section></td></tr></table></section><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">EXPLICIT</p><table style=\"width:100%;border-collapse:collapse;margin:4px 0;\"><tr><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">innerJoin('o.customer','c')\"] --> EB[\"开发者声明:<br/>INNER JOIN Customer c<br/>  ON o.customer_id = c.id</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">开发者声明:<br/>INNER JOIN Customer c<br/>  ON o.customer_id = c.id</p></section></td></tr></table></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">SELECT c.name<br/>FROM Order o<br/> LEFT JOIN Customer c ...</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">SELECT c.name<br/>FROM Order o<br/> INNER JOIN Customer c ...</p></section></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">隐式 JOIN 的问题场景</h3></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">\n  当实体中存在<strong style=\"color:#1a1a2e;font-weight:700;\">多条路径指向同一目标实体</strong>时，隐式 JOIN 可能导致意想不到的重复关联。\n</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// 实体模型：Order 同时有 createdBy 和 approvedBy 两个 User 关联</span><br/><span style=\"color:#6c7086;font-style:italic;\">// 隐式 JOIN 会为每条路径生成独立的 JOIN</span><br/>cb.select(\"o.createdBy.name\")    <span style=\"color:#6c7086;font-style:italic;\">// LEFT JOIN User u1 ON ...</span><br/>  .select(\"o.approvedBy.name\")   <span style=\"color:#6c7086;font-style:italic;\">// LEFT JOIN User u2 ON ...（不同路径 → 不同 JOIN）</span><br/><br/><span style=\"color:#6c7086;font-style:italic;\">// 显式 JOIN 让你精确控制别名和复用</span><br/>cb.leftJoin(\"o.createdBy\", \"creator\")<br/>  .leftJoin(\"o.approvedBy\", \"approver\")<br/>  .select(\"creator.name\")<br/>  .select(\"approver.name\");</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e0525244;border-radius:8px;padding:14px 16px;margin:14px 0 20px;font-size:14px;line-height:1.8;color:#2b2b2b;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">注意：</strong>隐式 JOIN 默认使用 LEFT JOIN。如果业务语义要求 INNER JOIN（即关联必须存在），\n  必须改用显式 JOIN 以避免返回不必要的 NULL 行。\n</section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">7.2 JOIN 类型</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">\n  Blaze-Persistence 支持 SQL 标准定义的四种 JOIN 类型，每种类型对未匹配行的处理方式不同。\n</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">四种 JOIN 类型 — 数据包含关系</p><p style=\"font-size:13px;color:#2b2b2b;line-height:2;margin:8px 0;\">\n\nINNER JOIN\n只返回两表都匹配的行\nOrder ∩ Customer\n\n\nLEFT JOIN\n返回左表所有行<br/>右表无匹配 → NULL\nOrder ∪ (Order ∩ Customer)\n\n\nRIGHT JOIN\n返回右表所有行<br/>左表无匹配 → NULL\n(Order ∩ Customer) ∪ Customer\n\n\nFULL JOIN\n返回两表所有行<br/>任一方无匹配 → NULL\nOrder ∪ Customer\n\n</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">四种 JOIN 的 API</h3></section>\n<section><table style=\"width:100%;border-collapse:collapse;margin:12px 0;font-size:14px;\"><tr><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">JOIN 类型</th><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">API 方法</th><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">SQL 生成</th><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">典型场景</th></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">INNER</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">innerJoin(path, alias)</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">INNER JOIN ... ON ...</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">关联必须存在（如订单必有客户）</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">LEFT</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">leftJoin(path, alias)</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">LEFT JOIN ... ON ...</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">关联可选（如订单可能没有优惠券）</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">RIGHT</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">rightJoin(path, alias)</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">RIGHT JOIN ... ON ...</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">以右表为主（少见，可用子查询替代）</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">FULL</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">join(path, alias, JoinType.FULL)</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">FULL OUTER JOIN ... ON ...</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">全量匹配报表（如对账）</td></tr></table></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// INNER JOIN — 只查有客户的订单</span><br/>CriteriaBuilder&lt;Order&gt; cb = cbf.create(em, Order.class)<br/>    .from(Order.class, \"o\")<br/>    .innerJoin(\"o.customer\", \"c\")<br/>    .where(\"c.country\").eq(\"CN\");<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// LEFT JOIN — 包含无明细的订单</span><br/>CriteriaBuilder&lt;Tuple&gt; cb2 = cbf.create(em, Tuple.class)<br/>    .from(Order.class, \"o\")<br/>    .leftJoin(\"o.items\", \"i\")<br/>    .select(\"o.id\").select(\"i.productName\");<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// RIGHT JOIN</span><br/>CriteriaBuilder&lt;Tuple&gt; cb3 = cbf.create(em, Tuple.class)<br/>    .from(Order.class, \"o\")<br/>    .rightJoin(\"o.customer\", \"c\")<br/>    .select(\"o.id\").select(\"c.name\");<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// FULL OUTER JOIN</span><br/>CriteriaBuilder&lt;Tuple&gt; cb4 = cbf.create(em, Tuple.class)<br/>    .from(Order.class, \"o\")<br/>    .join(\"o.customer\", \"c\", JoinType.FULL)<br/>    .select(\"o.id\").select(\"c.name\");</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">joinOn() — 自定义 JOIN 条件</h3></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">\n<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">joinOn()</code> 允许你在 JOIN 的 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">ON</code> 子句中附加额外条件，\n  而不是放在 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">WHERE</code> 中——这在 LEFT JOIN 场景下语义完全不同。\n</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">ON 条件 vs WHERE 条件 — 语义差异</p><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">ON_CLAUSE</p><table style=\"width:100%;border-collapse:collapse;margin:4px 0;\"><tr><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">LEFT JOIN items i<br/>  ON o.id = i.order_id<br/>  AND i.status = 'ACTIVE'</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">效果: 未匹配的 Order 仍保留<br/>i 列为 NULL</p></section></td></tr></table></section><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">WHERE_CLAUSE</p><table style=\"width:100%;border-collapse:collapse;margin:4px 0;\"><tr><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">LEFT JOIN items i<br/>  ON o.id = i.order_id<br/>WHERE i.status = 'ACTIVE'</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">效果: 过滤掉了 i 为 NULL 的行<br/>LEFT JOIN 退化为 INNER JOIN</p></section></td></tr></table></section></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">CriteriaBuilder&lt;Tuple&gt; cb = cbf.create(em, Tuple.class)<br/>    .from(Order.class, \"o\")<br/>    .leftJoinOn(\"o.items\", \"i\")             <span style=\"color:#6c7086;font-style:italic;\">// 开始 ON 条件</span><br/>        .on(\"i.status\").eq(ItemStatus.ACTIVE)<br/>    .end()                                   <span style=\"color:#6c7086;font-style:italic;\">// 结束 ON 条件</span><br/>    .select(\"o.id\")<br/>    .select(\"i.productName\");<br/><span style=\"color:#6c7086;font-style:italic;\">// SQL: LEFT JOIN OrderItem i ON o.id = i.order_id AND i.status = 'ACTIVE'</span></p></section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">7.3 FETCH JOIN</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">\n  FETCH JOIN 是解决 JPA 延迟加载 <strong style=\"color:#1a1a2e;font-weight:700;\">N+1 问题</strong>的核心手段。\n  Blaze-Persistence 通过 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">fetch()</code> API 让你在查询时声明需要预加载的关联，\n  将原本需要 N+1 次查询的场景合并为<strong style=\"color:#1a1a2e;font-weight:700;\">单次 JOIN 查询</strong>。\n</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">N+1 问题 vs FETCH JOIN — 查询次数对比</p><table style=\"width:100%;border-collapse:collapse;margin:0 0 8px;\"><tr><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">应用代码</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">Blaze-Persistence</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">数据库</th></tr></table><p style=\"text-align:center;font-size:11px;color:#888;background:#f5f5f5;border:1px solid #e6a81744;border-radius:4px;padding:4px 8px;margin:3px auto;max-width:80%;\">📌 ❌ 无 FETCH JOIN（N+1）</p><p style=\"text-align:center;font-size:11px;color:#888;background:#f5f5f5;border:1px solid #e6a81744;border-radius:4px;padding:4px 8px;margin:3px auto;max-width:80%;\">📌 总计: 1 + 10 = 11 次查询</p><p style=\"text-align:center;font-size:11px;color:#888;background:#f5f5f5;border:1px solid #e6a81744;border-radius:4px;padding:4px 8px;margin:3px auto;max-width:80%;\">📌 ✅ 使用 FETCH JOIN</p><p style=\"text-align:center;font-size:11px;color:#888;background:#f5f5f5;border:1px solid #e6a81744;border-radius:4px;padding:4px 8px;margin:3px auto;max-width:80%;\">📌 总计: 1 次查询</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">fetch() API 使用</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// 使用 fetch() 预加载关联</span><br/>CriteriaBuilder&lt;Order&gt; cb = cbf.create(em, Order.class)<br/>    .from(Order.class, \"o\")<br/>    .fetch(\"o.customer\")        <span style=\"color:#6c7086;font-style:italic;\">// FETCH JOIN Customer</span><br/>    .fetch(\"o.items\")           <span style=\"color:#6c7086;font-style:italic;\">// FETCH JOIN OrderItem</span><br/>    .where(\"o.status\").eq(OrderStatus.PENDING);<br/><span style=\"color:#6c7086;font-style:italic;\">// SQL: SELECT o FROM Order o</span><br/><span style=\"color:#6c7086;font-style:italic;\">//        JOIN FETCH o.customer</span><br/><span style=\"color:#6c7086;font-style:italic;\">//        JOIN FETCH o.items</span><br/><span style=\"color:#6c7086;font-style:italic;\">//      WHERE o.status = 'PENDING'</span></p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e0525244;border-radius:8px;padding:12px 14px;margin:4px 0;\"><p style=\"font-size:11px;font-weight:700;color:#e05252;margin-bottom:8px;\">❌ 错误示范</p><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// JPA 原生 JOIN FETCH</span><br/>em.createQuery(<br/>  \"SELECT o FROM Order o \" +<br/>  \"JOIN FETCH o.customer \" +<br/>  \"JOIN FETCH o.items \" +<br/>  \"WHERE o.status = :s\",<br/>  Order.class)<br/>  .setParameter(\"s\", \"PENDING\")<br/>  .getResultList();</p></section><section style=\"background:#f5f5f5;border:1px solid #1e6fff44;border-radius:8px;padding:12px 14px;margin:4px 0;\"><p style=\"font-size:11px;font-weight:700;color:#1e6fff;margin-bottom:8px;\">✅ 正确做法</p><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// Blaze-Persistence fetch()</span><br/>cbf.create(em, Order.class)<br/>  .from(Order.class, \"o\")<br/>  .fetch(\"o.customer\")<br/>  .fetch(\"o.items\")<br/>  .where(\"o.status\")<br/>    .eq(OrderStatus.PENDING)<br/>  .getResultList();</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #1e6fff44;border-radius:8px;padding:14px 16px;margin:14px 0 20px;font-size:14px;line-height:1.8;color:#2b2b2b;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">与 JPA JOIN FETCH 的区别：</strong>Blaze-Persistence 的 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">fetch()</code>\n  在 Entity View 场景下会自动优化为仅 SELECT 所需字段，而 JPA 的 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">JOIN FETCH</code>\n  总是加载完整实体。\n</section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">笛卡尔积陷阱</h3></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">\n  同时 FETCH JOIN <strong style=\"color:#1a1a2e;font-weight:700;\">多个集合关联</strong>会导致笛卡尔积——\n  如果 Order 有 3 个 Item 和 2 个 Payment，结果集膨胀为 3 × 2 = 6 行。\n</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">多集合 FETCH JOIN 的笛卡尔积问题</p><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">CARTESIAN</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">(Order#1, Item A, Payment X)</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">(Order#1, Item A, Payment Y)</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">(Order#1, Item B, Payment X)</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">(Order#1, Item B, Payment Y)</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">(Order#1, Item C, Payment X)</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">(Order#1, Item C, Payment Y)</p></section></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">Order #1\"] --> I1[\"Item A</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">Item A</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">Item B</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">Item C</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">Payment X</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">Payment Y</p></section></section>\n<section style=\"background:#f5f5f5;border:1px solid #e0525244;border-radius:8px;padding:14px 16px;margin:14px 0 20px;font-size:14px;line-height:1.8;color:#2b2b2b;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">规避策略：</strong>对于多集合关联，改用 <strong style=\"color:#1a1a2e;font-weight:700;\">SUBSELECT</strong> 或 <strong style=\"color:#1a1a2e;font-weight:700;\">MULTISET</strong>\n  FetchStrategy（详见 7.6 节），或将查询拆分为多次单集合 FETCH JOIN。\n  Hibernate 在检测到多 bag FETCH 时会抛出 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">MultipleBagFetchException</code>。\n</section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">7.4 关联路径表达式</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">\n  Blaze-Persistence 允许使用点号分隔的路径表达式进行<strong style=\"color:#1a1a2e;font-weight:700;\">多级实体导航</strong>。\n  框架会按路径的每一段自动创建所需的 JOIN，形成从根实体到目标属性的完整关联链。\n</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">路径表达式解析 — 实体图导航</p><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">SQL_GEN</p><table style=\"width:100%;border-collapse:collapse;margin:4px 0;\"><tr><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">LEFT JOIN Customer c<br/>  ON o.customer_id = c.id</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">LEFT JOIN Address a<br/>  ON c.address_id = a.id</p></section></td><td style=\"padding:4px;text-align:center;vertical-align:middle;\"><section style=\"padding:8px 6px;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:12px;font-weight:600;color:#1a1a2e;line-height:1.5;\">SELECT a.city</p></section></td></tr></table></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">Order o\"] -->|\"o.customer\"| CUSTOMER[\"Customer c</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">Customer c</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">Address a</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">city 属性</p></section></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">点号导航与 SQL 解析</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">CriteriaBuilder&lt;Tuple&gt; cb = cbf.create(em, Tuple.class)<br/>    .from(Order.class, \"o\")<br/>    <span style=\"color:#6c7086;font-style:italic;\">// 四级路径导航</span><br/>    .select(\"o.customer.address.city.name\")<br/>    <span style=\"color:#6c7086;font-style:italic;\">// 等效 SQL:</span><br/>    <span style=\"color:#6c7086;font-style:italic;\">// SELECT city.name FROM Order o</span><br/>    <span style=\"color:#6c7086;font-style:italic;\">//   LEFT JOIN Customer c    ON o.customer_id = c.id</span><br/>    <span style=\"color:#6c7086;font-style:italic;\">//   LEFT JOIN Address  a    ON c.address_id  = a.id</span><br/>    <span style=\"color:#6c7086;font-style:italic;\">//   LEFT JOIN City     city ON a.city_id     = city.id</span><br/>    .getResultList();</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e6a81744;border-radius:8px;padding:14px 16px;margin:14px 0 20px;font-size:14px;line-height:1.8;color:#2b2b2b;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">Embeddable 导航：</strong>如果路径中某段是 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@Embeddable</code> 而非独立实体，\n  Blaze-Persistence 不会为该段生成 JOIN，而是直接引用嵌入属性所在表的列。\n  例如 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">customer.contactInfo.phone</code> 中，<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">contactInfo</code> 是 Embeddable，\n  则只 JOIN Customer 表，直接读取其 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">contact_phone</code> 列。\n</section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Embeddable vs Entity 路径解析差异</p><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">ENTITY_PATH</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">Order o\"] -->|\"JOIN\"| EP2[\"Customer c</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">Customer c</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">Address a</p></section></section><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">EMBED_PATH</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">Customer c\"] -->|\"无 JOIN<br/>直接列引用\"| EB2[\"c.contact_phone</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">c.contact_phone</p></section></section></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">\n  路径表达式还支持集合导航。对集合属性使用路径会隐式产生 JOIN，\n  随后可用聚合函数或 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">SIZE</code> 表达式对集合进行计算：\n</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// 集合路径 + 聚合</span><br/>CriteriaBuilder&lt;Tuple&gt; cb = cbf.create(em, Tuple.class)<br/>    .from(Order.class, \"o\")<br/>    .select(\"o.id\")<br/>    .select(\"SIZE(o.items)\")             <span style=\"color:#6c7086;font-style:italic;\">// 隐式 JOIN + COUNT</span><br/>    .select(\"o.items.price\").max()       <span style=\"color:#6c7086;font-style:italic;\">// 隐式 JOIN + MAX</span><br/>    .groupBy(\"o.id\");</p></section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">7.5 跨实体关联与 Lateral JOIN</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">\n  标准 JPA 只能 JOIN 实体间已声明的 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@ManyToOne</code> / <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@OneToMany</code> 等映射关联。\n  Blaze-Persistence 突破了这一限制，允许<strong style=\"color:#1a1a2e;font-weight:700;\">跨实体关联</strong>——\n  即 JOIN 两个没有映射关系的实体，并通过 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">ON</code> 条件手动指定关联条件。\n</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">跨实体关联与 Lateral JOIN 架构</p><section style=\"margin:3px 0;padding:8px 12px;background:rgb(248,81,73);border-left:3px solid #f85149;border-radius:4px;\"><p style=\"margin:0;font-size:12px;line-height:1.6;\"><span style=\"color:#f85149;\">标准 JPA JOIN</span> <span style=\"color:#e6edf3;\">只能 JOIN 已映射关联Order →(ManyToOne)→ Customer</span> <span style=\"color:#f85149;\">受限于实体映射</span></p></section><section style=\"margin:3px 0;padding:8px 12px;background:rgb(63,185,80);border-left:3px solid #3fb950;border-radius:4px;\"><p style=\"margin:0;font-size:12px;line-height:1.6;\"><span style=\"color:#3fb950;\">跨实体关联 (BP)</span> <span style=\"color:#e6edf3;\">JOIN 无映射关系的实体通过 ON 条件手动关联Order ←ON→ AuditLog</span> <span style=\"color:#3fb950;\">灵活的跨表查询</span></p></section><section style=\"margin:3px 0;padding:8px 12px;background:rgb(188,140,255);border-left:3px solid #bc8cff;border-radius:4px;\"><p style=\"margin:0;font-size:12px;line-height:1.6;\"><span style=\"color:#bc8cff;\">Lateral JOIN</span> <span style=\"color:#e6edf3;\">子查询可引用外层表的列每行外层数据驱动一次子查询类似 SQL 的 LATERAL / APPLY</span> <span style=\"color:#bc8cff;\">强大的行级子查询</span></p></section></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// 跨实体关联：Order 与 AuditLog 没有 JPA 映射</span><br/>CriteriaBuilder&lt;Tuple&gt; cb = cbf.create(em, Tuple.class)<br/>    .from(Order.class, \"o\")<br/>    .leftJoinOn(AuditLog.class, \"log\")<br/>        .on(\"log.entityId\").eqExpression(\"o.id\")<br/>        .on(\"log.entityType\").eq(\"ORDER\")<br/>    .end()<br/>    .select(\"o.id\")<br/>    .select(\"log.action\")<br/>    .select(\"log.timestamp\");</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">Lateral JOIN 支持矩阵</h3></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">\n  Lateral JOIN（也称 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">CROSS APPLY</code> / <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">OUTER APPLY</code>）允许子查询引用外层查询的列。\n  Blaze-Persistence 在支持该特性的数据库上可生成对应 SQL。\n</p></section>\n<section><table style=\"width:100%;border-collapse:collapse;margin:12px 0;font-size:14px;\"><tr><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">数据库</th><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">Lateral JOIN</th><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">语法</th><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">备注</th></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">PostgreSQL</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">✅ 支持</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">LATERAL</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">9.3+ 原生支持</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">Oracle</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">✅ 支持</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">LATERAL</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">12c+ 原生支持</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">SQL Server</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">✅ 支持</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">CROSS APPLY / OUTER APPLY</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">2005+ 支持</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">MySQL</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">✅ 支持</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">LATERAL</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">8.0.14+ 支持</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">H2</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">⚠️ 有限</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">—</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">部分版本不支持，测试时注意</td></tr></table></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Lateral JOIN 执行模型</p><table style=\"width:100%;border-collapse:collapse;margin:0 0 8px;\"><tr><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">外层查询 (Order)</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">Lateral 子查询</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">数据库引擎</th></tr></table></section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">7.6 Entity View 中的 JOIN 控制</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">\n  在 Entity View 层面，Blaze-Persistence 提供四种 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">FetchStrategy</code>\n  来控制关联数据的加载方式。每种策略生成截然不同的 SQL 模式，\n  适用于不同的数据规模和性能需求。\n</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">四种 FetchStrategy — SQL 生成模式对比</p><p style=\"font-size:13px;color:#2b2b2b;line-height:2;margin:8px 0;\">\n\nJOIN 策略\n单一查询 + JOIN\nSELECT o.*, i.* FROM Order o LEFT JOIN Item i\n✅ 最少查询次数<br/>\n\n\nSELECT 策略\n主查询 + N 次子查询\nSELECT * FROM Item WHERE order_id = ? (× N)\n✅ 无笛卡尔积<br/>\n\n\nSUBSELECT 策略\n主查询 + 1 次批量子查询\nSELECT * FROM Item WHERE order_id IN (SELECT ...)\n✅ 无笛卡尔积<br/>\n\n\nMULTISET 策略\n单一查询 + 嵌套集合\nSELECT o.*, (SELECT ... FROM Item) FROM Order\n✅ 单次查询 · ✅ 无笛卡尔积<br/>\n\n</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">代码示例与策略选择</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">@EntityView(Order.class)<br/>public interface OrderView {<br/><br/>    @IdMapping<br/>    Long getId();<br/><br/>    <span style=\"color:#6c7086;font-style:italic;\">// JOIN 策略（默认）— 单一查询</span><br/>    @Mapping(fetch = FetchStrategy.JOIN)<br/>    CustomerView getCustomer();<br/><br/>    <span style=\"color:#6c7086;font-style:italic;\">// SUBSELECT 策略 — 批量加载集合</span><br/>    @Mapping(fetch = FetchStrategy.SUBSELECT)<br/>    List&lt;OrderItemView&gt; getItems();<br/><br/>    <span style=\"color:#6c7086;font-style:italic;\">// MULTISET 策略 — 嵌套集合，单次查询</span><br/>    @Mapping(fetch = FetchStrategy.MULTISET)<br/>    List&lt;PaymentView&gt; getPayments();<br/>}</p></section>\n<section><table style=\"width:100%;border-collapse:collapse;margin:12px 0;font-size:14px;\"><tr><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">策略</th><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">查询次数</th><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">笛卡尔积</th><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">适用场景</th></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">JOIN</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">1</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">⚠️ 多集合时有风险</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">单一集合或 @ManyToOne 关联</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">SELECT</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">N+1</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">✅ 无</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">少量主记录时可接受</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">SUBSELECT</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">2</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">✅ 无</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">大量主记录 + 集合关联</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\"><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">MULTISET</code></td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">1</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">✅ 无</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">多集合场景的最优解（需 DB 支持）</td></tr></table></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">策略选择决策树</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">需要加载关联数据</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #e6a817;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">◇ 关联类型?</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">✅ JOIN 策略<br/>单次查询即可</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #e6a817;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">◇ 有几个集合需要加载?</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">✅ JOIN 策略<br/>无笛卡尔积风险</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #e6a817;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">◇ 数据库支持 MULTISET?</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">✅ MULTISET 策略<br/>单查询 + 无笛卡尔积</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #e6a817;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">◇ 主记录数量?</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">SELECT 策略<br/>简单但有 N+1</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">✅ SUBSELECT 策略<br/>2 次查询 + 无笛卡尔积</p></section></section>\n<section style=\"background:#f5f5f5;border:1px solid #1e6fff44;border-radius:8px;padding:14px 16px;margin:14px 0 20px;font-size:14px;line-height:1.8;color:#2b2b2b;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">📖 参考：</strong><code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@MappingFetch</code> 注解允许在 Entity View 的集合映射上\n  指定 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">FetchStrategy</code>，覆盖默认行为。结合 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@BatchSize</code> 可进一步优化\n  SELECT 策略的批量加载粒度。\n</section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">7.7 陷阱与限制</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">\n  JOIN 是性能调优中最需要谨慎的部分。以下列出生产环境中最常见的陷阱。\n</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">JOIN 常见陷阱全景图</p><p style=\"font-size:13px;color:#2b2b2b;line-height:2;margin:8px 0;\">\n\n陷阱 1: 笛卡尔积\n多集合 FETCH JOIN<br/>\n解决: SUBSELECT / MULTISET\n\n\n陷阱 2: 隐式 JOIN 去重\n相同路径自动去重<br/>不同路径到同一实体 → 多个 JOIN\n解决: 使用显式 JOIN + 别名\n\n\n陷阱 3: FETCH + 分页\nHibernate 警告 HHH000104<br/>内存中分页! 全量加载后裁剪\n解决: 先分页 ID, 再 FETCH JOIN\n\n\n陷阱 4: 深层 JOIN 链\no.a.b.c.d.e.f — 6 层 JOIN<br/>SQL 复杂度指数增长\n解决: 子查询 / Entity View 拆分\n\n</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">陷阱 1: 多集合 FETCH JOIN 的笛卡尔积</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// ❌ 危险: 同时 FETCH 两个集合</span><br/>CriteriaBuilder&lt;Order&gt; cb = cbf.create(em, Order.class)<br/>    .from(Order.class, \"o\")<br/>    .fetch(\"o.items\")       <span style=\"color:#6c7086;font-style:italic;\">// 集合 1</span><br/>    .fetch(\"o.payments\");   <span style=\"color:#6c7086;font-style:italic;\">// 集合 2 → 笛卡尔积!</span><br/><br/><span style=\"color:#6c7086;font-style:italic;\">// ✅ 安全: 使用 SUBSELECT 策略</span><br/>@EntityView(Order.class)<br/>public interface SafeOrderView {<br/>    @Mapping(fetch = FetchStrategy.JOIN)<br/>    List&lt;OrderItemView&gt; getItems();        <span style=\"color:#6c7086;font-style:italic;\">// 只有一个用 JOIN</span><br/><br/>    @Mapping(fetch = FetchStrategy.SUBSELECT)<br/>    List&lt;PaymentView&gt; getPayments();       <span style=\"color:#6c7086;font-style:italic;\">// 另一个用 SUBSELECT</span><br/>}</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">陷阱 2: FETCH JOIN 与分页冲突</h3></section>\n<section style=\"background:#f5f5f5;border:1px solid #e0525244;border-radius:8px;padding:14px 16px;margin:14px 0 20px;font-size:14px;line-height:1.8;color:#2b2b2b;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">Hibernate 内存分页：</strong>当 FETCH JOIN 集合与 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">setFirstResult / setMaxResults</code>\n  同时使用时，Hibernate 会发出警告 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">HHH000104</code>，\n  并在内存中执行分页（先加载全部数据再裁剪）。这在大数据量下会导致 OOM。\n</section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// ❌ 危险组合</span><br/>CriteriaBuilder&lt;Order&gt; cb = cbf.create(em, Order.class)<br/>    .from(Order.class, \"o\")<br/>    .fetch(\"o.items\")<br/>    .setFirstResult(0)<br/>    .setMaxResults(20);  <span style=\"color:#6c7086;font-style:italic;\">// Hibernate 内存分页!</span><br/><br/><span style=\"color:#6c7086;font-style:italic;\">// ✅ 安全: 两阶段查询</span><br/><span style=\"color:#6c7086;font-style:italic;\">// 阶段 1: 分页取 ID</span><br/>List&lt;Long&gt; ids = cbf.create(em, Long.class)<br/>    .from(Order.class, \"o\")<br/>    .select(\"o.id\")<br/>    .setFirstResult(0)<br/>    .setMaxResults(20)<br/>    .getResultList();<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// 阶段 2: 用 ID 批量 FETCH</span><br/>CriteriaBuilder&lt;Order&gt; cb = cbf.create(em, Order.class)<br/>    .from(Order.class, \"o\")<br/>    .fetch(\"o.items\")<br/>    .where(\"o.id\").in(ids);</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">陷阱 3: 深层 JOIN 链的性能影响</h3></section>\n<section style=\"margin:12px 0 20px;\"><section style=\"display:inline-block;min-width:100px;background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:12px 14px;text-align:center;margin:4px 6px 4px 0;\"><p style=\"margin:0;font-size:22px;font-weight:800;color:#1e6fff;\">2-3</p><p style=\"margin:4px 0 0;font-size:10px;color:#888;text-transform:uppercase;letter-spacing:.5px;\">推荐 JOIN 深度</p></section><section style=\"display:inline-block;min-width:100px;background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:12px 14px;text-align:center;margin:4px 6px 4px 0;\"><p style=\"margin:0;font-size:22px;font-weight:800;color:#1e6fff;\">5+</p><p style=\"margin:4px 0 0;font-size:10px;color:#888;text-transform:uppercase;letter-spacing:.5px;\">性能警戒线</p></section><section style=\"display:inline-block;min-width:100px;background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:12px 14px;text-align:center;margin:4px 6px 4px 0;\"><p style=\"margin:0;font-size:22px;font-weight:800;color:#1e6fff;\">O(n!)</p><p style=\"margin:4px 0 0;font-size:10px;color:#888;text-transform:uppercase;letter-spacing:.5px;\">执行计划复杂度</p></section></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">陷阱 4: Provider 差异</h3></section>\n<section><table style=\"width:100%;border-collapse:collapse;margin:12px 0;font-size:14px;\"><tr><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">行为</th><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">Hibernate</th><th style=\"background:#f5f5f5;text-align:left;padding:8px 12px;font-weight:600;font-size:13px;color:#555;border:1px solid #e5e7eb;\">EclipseLink</th></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">隐式 JOIN 默认类型</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">LEFT JOIN</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">INNER JOIN</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">多 bag FETCH JOIN</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">抛出异常</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">允许（但有笛卡尔积）</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">FETCH + 分页</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">内存分页 + 警告</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">静默截断</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">Lateral JOIN 支持</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">6.x+ 部分支持</td><td style=\"padding:8px 12px;border:1px solid #e5e7eb;color:#2b2b2b;font-size:14px;\">不支持</td></tr></table></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">安全 JOIN 策略检查清单</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">编写 JOIN 查询</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #e6a817;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">◇ 多个集合<br/>FETCH JOIN?</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">改用 SUBSELECT<br/>或 MULTISET</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #e6a817;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">◇ JOIN + 分页?</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">两阶段查询:<br/>先分页 ID,<br/>再 FETCH</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #e6a817;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">◇ JOIN 深度 > 3?</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">拆分子查询<br/>或 Entity View</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #e6a817;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">◇ 跨 Provider?</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">显式指定 JOIN 类型<br/>避免隐式差异</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">✅ 安全</p></section></section>\n<section style=\"background:#f5f5f5;border:1px solid #1e6fff22;border-radius:10px;padding:20px 22px;margin:36px 0 16px;\"><p style=\"font-size:18px;font-weight:700;color:#1e6fff;margin:0 0 12px;\">📋 📝 本章小结</p><ul style=\"margin:8px 0 12px 20px;color:#2b2b2b;\"><li style=\"margin-bottom:5px;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">隐式 vs 显式 JOIN：</strong>路径表达式触发隐式 LEFT JOIN，显式 API 提供完整的类型和别名控制</li><li style=\"margin-bottom:5px;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">四种 JOIN 类型：</strong>INNER / LEFT / RIGHT / FULL 各有语义，<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">joinOn()</code> 支持自定义 ON 条件</li><li style=\"margin-bottom:5px;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">FETCH JOIN：</strong>通过 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">fetch()</code> 将 N+1 查询合并为单次查询，但需警惕多集合的笛卡尔积</li><li style=\"margin-bottom:5px;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">路径表达式：</strong>点号导航自动解析为 JOIN 链，Embeddable 段不产生额外 JOIN</li><li style=\"margin-bottom:5px;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">跨实体关联：</strong>Blaze-Persistence 突破 JPA 映射限制，支持无关联实体的 JOIN 和 Lateral JOIN</li><li style=\"margin-bottom:5px;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">FetchStrategy：</strong>JOIN / SELECT / SUBSELECT / MULTISET 四策略适配不同场景，MULTISET 是多集合最优解</li><li style=\"margin-bottom:5px;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">安全清单：</strong>避免多集合 FETCH + 分页组合，限制 JOIN 深度，注意 Provider 行为差异</li></ul><p style=\"font-size:13px;color:#888;margin-top:10px;padding-top:10px;border-top:1px solid #e5e7eb;\">\n    下一章 → <span style=\"color:#1e6fff;\">第 8 章 · CTE 与集合操作</span>：\n    探索公共表达式 (CTE)、递归查询以及 UNION / INTERSECT / EXCEPT 集合操作在 Blaze-Persistence 中的实现。\n  </p></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">© 2026 图解 Blaze-Persistence · 第 7 章 · JOIN 与关联策略</p></section>";
  await page.waitForSelector('.ProseMirror', { timeout: 15000 });
  if (title) {
    var ti = page.locator('textarea[placeholder="请在这里输入标题"]');
    await ti.fill(title);
    await page.waitForTimeout(300);
  }
  await page.evaluate((h) => {
    var pm = document.querySelector('.ProseMirror');
    pm.focus();
    var dt = new DataTransfer();
    dt.setData('text/html', h);
    var ev = new ClipboardEvent('paste', {bubbles:true, cancelable:true, clipboardData:dt});
    pm.dispatchEvent(ev);
  }, html);
  await page.waitForTimeout(1500);
  var enableBtns = page.locator('label:has-text("开启")');
  var cnt = await enableBtns.count();
  for (var i = 0; i < cnt; i++) {
    try {
      var b = enableBtns.nth(i);
      if (await b.isVisible({ timeout: 500 })) await b.click({ timeout: 1000 });
    } catch(e) {}
  }
  await page.waitForTimeout(500);
  var saveBtn = page.getByRole('button', { name: '保存为草稿' });
  await saveBtn.click();
  await page.waitForTimeout(2000);
  return title + ' -> saved';
}